// استخراج التوكن من الـ response
const jsonData = pm.response.json();pm.environment.get("{{BASE_URL}}")

// غير $.access_token حسب مسار التوكن في الـ response بتاعك
const token = jsonData.access_token || jsonData.token || jsonData.data?.access_token;

// تخزينه كـ Global Variable
pm.globals.set("ACCESS_TOKEN", token);

